package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import org.junit.jupiter.api.Test;

import java.lang.reflect.Constructor;

class LineItemTest {

  @Test
  void testGetQuantity() throws Exception {
    String name = "Test Item";
    int quantity = 5;
    long priceInMicros = 100000L;
    String currencyCode = "USD";

    // Directly use the LineItem class instead of Class.forName
    Constructor<LineItem> constructor = LineItem.class.getDeclaredConstructor(String.class, int.class, long.class, String.class);
    LineItem lineItem = constructor.newInstance(name, quantity, priceInMicros, currencyCode);

    int actualQuantity = lineItem.getQuantity();

    assertEquals(quantity, actualQuantity);
  }
}
